module ripple_carry_adder (
    input [3:0] anti_a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);

wire c1, c2, c3;

full_adder fa0 (.anti_a(anti_a[0]), .b(b[0]), .cin(cin),  .sum(sum[0]), .cout(c1));
full_adder fa1 (.anti_a(anti_a[1]), .b(b[1]), .cin(c1), .sum(sum[1]), .cout(c2));
full_adder fa2 (.anti_a(anti_a[2]), .b(b[2]), .cin(c2), .sum(sum[2]), .cout(c3));
full_adder fa3 (.anti_a(anti_a[3]), .b(b[3]), .cin(c3), .sum(sum[3]), .cout(cout));

endmodule
